// Check if current time is within business hours (UAE timezone)
const now = new Date();

// Convert to UAE time (UTC+4)
const uaeTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Dubai' }));
const hour = uaeTime.getHours();
const day = uaeTime.getDay(); // 0=Sunday, 5=Friday, 6=Saturday

// Business hours configuration
// Saturday-Thursday: 9 AM - 10 PM
// Friday: 2 PM - 10 PM (after Jummah)
let isOpen = false;
let nextOpenTime = '';

if (day === 5) {
  // Friday
  isOpen = hour >= 14 && hour < 22;
  if (hour < 14) nextOpenTime = '2:00 PM today';
  else if (hour >= 22) nextOpenTime = '9:00 AM tomorrow';
} else {
  // Saturday - Thursday
  isOpen = hour >= 9 && hour < 22;
  if (hour < 9) nextOpenTime = '9:00 AM today';
  else if (hour >= 22) {
    nextOpenTime = day === 4 ? '2:00 PM tomorrow (Friday)' : '9:00 AM tomorrow';
  }
}

return [{
  json: {
    isOpen,
    currentTime: uaeTime.toLocaleString('en-US', { timeZone: 'Asia/Dubai' }),
    hour,
    day,
    dayName: ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][day],
    nextOpenTime,
    message: $input.all()[0].json.body?.message || '',
    phone: $input.all()[0].json.body?.phone || '',
    name: $input.all()[0].json.body?.name || ''
  }
}];
